#!/usr/bin/env bash # pick-framework.sh — apply the 9-framework matrix to a market-context file. # Inputs: .aidocs/product_docs/market-context.yml # Output: .aidocs/product_docs/framework-choice.md (versioned via git) set -euo pipefail ctx=".aidocs/product_docs/market-context.yml" out=".aidocs/product_docs/framework-choice.md" [ -f "$ctx" ] || { echo "missing $ctx — run market-researcher agent first" >&2; exit 2; } mkdir -p "$(dirname "$out")" python3 - "$ctx" "$out" <<'PY' import sys, yaml, datetime ctx = yaml.safe_load(open(sys.argv[1])); out = sys.argv[2] m = ctx.get("market_condition", "").lower(); b = ctx.get("buyer", "").lower() diff = ctx.get("differentiator", "").lower(); tech = ctx.get("tech_uncertainty", False) rules = [ (lambda: tech, "MFP", "Technical feasibility unknown — prove infra first."), (lambda: "enterprise" in b or "b2b" in b, "MMP", "Enterprise buyer needs sellable surface."), (lambda: "crowded" in m or "red ocean" in m, "MLP", "Crowded market — emotional differentiation required."), (lambda: "premium" in diff or "luxury" in diff, "MDP", "Premium positioning needs delight."), (lambda: "high uncertainty" in ctx.get("risk_profile", "").lower(), "RAT", "Validate riskiest assumption before scope."), (lambda: "consumer" in b and "simple" in diff, "SLC", "Consumer + simplicity — Simple/Lovable/Complete."), (lambda: True, "MVP", "Default: blue ocean, low cost, fast learning."), ] chosen, why = next((f, w) for cond, f, w in rules if cond()) with open(out, "w") as f: f.write(f"# Framework choice — {datetime.date.today().isoformat()}

") f.write(f"**Chosen:** {chosen}

**Rationale:** {why}

") f.write("## Inputs
```yaml
" + yaml.safe_dump(ctx) + "```

") f.write("## Exit criteria
- TODO: define metric + threshold
- TODO: define kill-criterion
") f.write("
## History
- " + datetime.date.today().isoformat() + f": initial pick = {chosen}
") print(out, chosen) PY git add "$out"
